data.transition-전환#Transition (전환):
긴급한 업데이트와 그렇지 않은 업데이트를 명시적으로 구분하는 개념이다.React 18 이전까지는 모든 상태의 업데이트가 동일한 우선순위를 가지고 있었다.그렇기 때문에 Debounce / Throttle 등의 기법을 활용하여 간접적으로 우선순위를 구분하였다.React 18부터는 startTransitionAPI를 통해 전환 업데이트를 명시적으로 구분한다.
import React, { useState, useTransition, Suspense } from 'react';
import { testApi } from './api';
function MyComponent() {
  const [data, setData] = useState(null);
  const [isPending, startTransition] = useTransition({
    timeoutMs: 3000, 
  });
  const fetchData = async () => {
    const receivedData = await testApi();
    setData(receivedData);
  };
  const handleFetchData = () => {
    startTransition(() => {
      fetchData();
    });
  };
  return (
    <div>
      {isPending ? (
        <div>Loading...</div>
      ) : (
        <Suspense fallback={<div>Loading...</div>}>
          <button
            onClick={handleFetchData}
            disabled={isPending}
          >
            {isPending ? 'Fetching...' : 'Fetch Data'}
          </button>
          {data && (
            <div>
              <h2>Data:</h2>
              <p>{data}</p>
            </div>
          )}
        </Suspense>
      )}
    </div>
  );
}
export default MyComponent;

